package com.xoxo.pos.expenses;import org.springframework.web.bind.annotation.*;import java.time.LocalDate;import java.util.List;@RestController @RequestMapping("/api/expenses") public class ExpenseController{private final ExpenseRepository repo;public ExpenseController(ExpenseRepository repo){this.repo=repo;}@GetMapping("/today") public List<Expense> today(){var s=LocalDate.now().atStartOfDay();return repo.findByCreatedAtBetweenOrderByCreatedAtDesc(s,s.plusDays(1));}@PostMapping public Expense create(@RequestBody Expense e){if(e.getCreatedAt()==null)e.setCreatedAt(java.time.LocalDateTime.now());return repo.save(e);}@DeleteMapping("/{id}") public void delete(@PathVariable Long id){repo.deleteById(id);}}
